// Compiles the contributor-friendly YAML crafting guides in `guides/*.yaml`
// into a typed TS module the app imports (`src/lib/crafting.generated.ts`).
//
// What it does:
//   1. Loads the vendored item dataset (`src/lib/poe2-items.json`, generated by
//      the website's tools/consolidate-poe2-data.mjs) to map item name → icon in
//      the shared `static/poe2/` tree. Guides reference items by *name* only.
//   2. Parses + validates every guide, collecting ALL problems before exiting so
//      a contributor sees every issue at once (bad slot, unknown item, …).
//   3. Resolves each item name to its icon and writes the generated module.
//
// Run via `bun run crafting` (chained into dev/build/check). A validation
// failure exits non-zero, so a broken guide fails the build instead of shipping.

import { readFileSync, writeFileSync, readdirSync, existsSync } from 'node:fs';
import { join } from 'node:path';
import { fileURLToPath } from 'node:url';
import { parse as parseYaml } from 'yaml';

const ROOT = fileURLToPath(new URL('..', import.meta.url));
const GUIDES_DIR = join(ROOT, 'guides');
const DATA_FILE = join(ROOT, 'src', 'lib', 'poe2-items.json');
const OUT_FILE = join(ROOT, 'src', 'lib', 'crafting.generated.ts');

// Must match the EquipmentSlot union + EQUIPMENT_SLOTS in src/lib/crafting.ts.
const SLOTS = ['weapon', 'offhand', 'quiver', 'helmet', 'body', 'gloves', 'boots', 'belt', 'amulet', 'ring', 'jewel'];

const asString = (v) => (typeof v === 'string' ? v : undefined);

/** Build a map of item display name → icon URL from the vendored dataset. */
function loadIconMap() {
  if (!existsSync(DATA_FILE)) {
    console.error(`[crafting] Missing ${DATA_FILE.replace(ROOT, '')}.`);
    console.error('  Generate it from the website: `bun run consolidate`.');
    process.exit(1);
  }
  const data = JSON.parse(readFileSync(DATA_FILE, 'utf8'));
  /** @type {Map<string, string>} */
  const icons = new Map();
  for (const entry of [...(data.bases ?? []), ...(data.materials ?? [])]) {
    if (entry.icon) icons.set(entry.name, `/poe2/${entry.icon}`);
  }
  return icons;
}

/** Resolve a YAML item (an item-name string) to `{ name, icon }`. */
function resolveItem(raw, ctx, errors, icons) {
  const name = typeof raw === 'string' ? raw : raw && typeof raw.name === 'string' ? raw.name : undefined;
  if (name === undefined) {
    errors.push(`${ctx}: item must be an item-name string`);
    return { name: String(raw), icon: '' };
  }
  const icon = icons.get(name);
  if (!icon) {
    errors.push(`${ctx}: no icon found for "${name}". It must be a known PoE2 item name (the guide creator lists valid names).`);
    return { name, icon: '' };
  }
  return { name, icon };
}

function validateBranch(b, ctx, errors, catalog) {
  if (!b || typeof b !== 'object') {
    errors.push(`${ctx}: must be a mapping with "if" and "text"`);
    return { kind: 'fail', text: '' };
  }
  const ifVal = asString(b.if) ?? asString(b.kind);
  const text = asString(b.text);
  if (!text) errors.push(`${ctx}: missing "text"`);
  let out;
  if (ifVal === 'success' || ifVal === 'fail') {
    out = { kind: ifVal, text: text ?? '' };
  } else if (ifVal && ifVal.trim()) {
    out = { kind: 'custom', label: ifVal.trim(), text: text ?? '' };
  } else {
    errors.push(`${ctx}: "if" must be "success", "fail", or a condition label`);
    out = { kind: 'fail', text: text ?? '' };
  }
  if (b.items != null) {
    if (!Array.isArray(b.items)) errors.push(`${ctx}: "items" must be a list`);
    else out.items = b.items.map((it, i) => resolveItem(it, `${ctx} › item ${i + 1}`, errors, catalog));
  }
  return out;
}

function validateStep(s, ctx, errors, catalog, stepIds) {
  if (!s || typeof s !== 'object') {
    errors.push(`${ctx}: must be a mapping`);
    return { id: '', title: '' };
  }
  const id = asString(s.id);
  const title = asString(s.title);
  if (!id) errors.push(`${ctx}: missing "id"`);
  else if (stepIds.has(id)) errors.push(`${ctx}: duplicate step id "${id}"`);
  else stepIds.add(id);
  if (!title) errors.push(`${ctx}: missing "title"`);

  const out = { id: id ?? '', title: title ?? '' };
  const detail = asString(s.detail);
  if (detail) out.detail = detail;
  if (s.optional != null) {
    if (typeof s.optional !== 'boolean') errors.push(`${ctx}: "optional" must be true or false`);
    else if (s.optional) out.optional = true;
  }
  if (s.note != null) {
    if (typeof s.note !== 'object') {
      errors.push(`${ctx}: "note" must be a { kind, text } mapping`);
    } else {
      const kind = asString(s.note.kind);
      const noteText = asString(s.note.text);
      if (!NOTE_KINDS.includes(kind)) {
        errors.push(`${ctx}: note "kind" must be one of: ${NOTE_KINDS.join(', ')}`);
      } else if (!noteText || !noteText.trim()) {
        errors.push(`${ctx}: note needs "text"`);
      } else {
        out.note = { kind, text: noteText };
      }
    }
  }
  if (s.items != null) {
    if (!Array.isArray(s.items)) errors.push(`${ctx}: "items" must be a list`);
    else out.items = s.items.map((it, i) => resolveItem(it, `${ctx} › item ${i + 1}`, errors, catalog));
  }
  if (s.targets != null) {
    if (!Array.isArray(s.targets)) errors.push(`${ctx}: "targets" must be a list`);
    else out.targets = s.targets.map((t, i) => validateTarget(t, `${ctx} › target ${i + 1}`, errors));
  }
  if (s.repeat != null) {
    if (typeof s.repeat !== 'boolean') errors.push(`${ctx}: "repeat" must be true or false`);
    else if (s.repeat) out.repeat = true;
  }
  if (s.branches != null) {
    if (!Array.isArray(s.branches)) errors.push(`${ctx}: "branches" must be a list`);
    else out.branches = s.branches.map((b, i) => validateBranch(b, `${ctx} › branch ${i + 1}`, errors, catalog));
  }
  return out;
}

const RESULT_TAGS = ['prefix', 'suffix', 'fractured', 'implicit'];
const NOTE_KINDS = ['tip', 'warning', 'alt'];

/** Resolve a result mod (a string, or `{ text, tag, alt }`). */
function validateResultMod(raw, ctx, errors) {
  let text, tag, alt;
  if (typeof raw === 'string') {
    text = raw;
  } else if (raw && typeof raw === 'object' && typeof raw.text === 'string') {
    text = raw.text;
    tag = asString(raw.tag);
    alt = raw.alt;
  } else {
    errors.push(`${ctx}: must be a mod-text string or a { text, tag, alt } mapping`);
    return { text: String(raw) };
  }
  if (!text.trim()) errors.push(`${ctx}: missing "text"`);
  const out = { text };
  if (tag != null) {
    if (!RESULT_TAGS.includes(tag)) {
      errors.push(`${ctx}: invalid tag "${tag}" (expected one of: ${RESULT_TAGS.join(', ')})`);
    } else {
      out.tag = tag;
    }
  }
  if (alt != null) {
    if (typeof alt !== 'boolean') errors.push(`${ctx}: "alt" must be true or false`);
    else if (alt) out.alt = true;
  }
  return out;
}

const isHttpUrl = (s) => /^https?:\/\//i.test(s);

/** Validate an author block: `{ name, youtube?, twitch? }`. */
function validateAuthor(raw, ctx, errors) {
  if (typeof raw !== 'object' || raw === null) {
    errors.push(`${ctx}: "author" must be a { name, youtube?, twitch? } mapping`);
    return undefined;
  }
  const name = asString(raw.name);
  if (!name || !name.trim()) errors.push(`${ctx}: author needs a "name"`);
  const out = { name: name ?? '' };
  for (const key of ['youtube', 'twitch']) {
    const url = asString(raw[key]);
    if (url != null && url.trim()) {
      if (!isHttpUrl(url.trim())) errors.push(`${ctx}: author ${key} must be an http(s) URL`);
      else out[key] = url.trim();
    }
  }
  return out;
}

/** Resolve a step target mod (a string, or `{ text, tag }`). */
function validateTarget(raw, ctx, errors) {
  let text, tag;
  if (typeof raw === 'string') {
    text = raw;
  } else if (raw && typeof raw === 'object' && typeof raw.text === 'string') {
    text = raw.text;
    tag = asString(raw.tag);
  } else {
    errors.push(`${ctx}: must be a mod-text string or a { text, tag } mapping`);
    return { text: String(raw) };
  }
  if (!text.trim()) errors.push(`${ctx}: missing "text"`);
  const out = { text };
  if (tag != null) {
    if (!RESULT_TAGS.includes(tag)) {
      errors.push(`${ctx}: invalid tag "${tag}" (expected one of: ${RESULT_TAGS.join(', ')})`);
    } else {
      out.tag = tag;
    }
  }
  return out;
}

function validateGuide(doc, ctx, errors, catalog, ids) {
  const id = asString(doc.id);
  const slot = asString(doc.slot);
  const name = asString(doc.name);
  const goal = asString(doc.goal);

  if (!id) errors.push(`${ctx}: missing "id"`);
  else if (ids.has(id)) errors.push(`${ctx}: duplicate guide id "${id}" (must be unique across all guides)`);
  else ids.add(id);
  if (!slot) errors.push(`${ctx}: missing "slot"`);
  else if (!SLOTS.includes(slot)) errors.push(`${ctx}: invalid slot "${slot}" (expected one of: ${SLOTS.join(', ')})`);
  if (!name) errors.push(`${ctx}: missing "name"`);
  if (!goal) errors.push(`${ctx}: missing "goal"`);

  let bases = [];
  if (doc.base == null) {
    errors.push(`${ctx}: missing "base" item`);
  } else {
    const rawBases = Array.isArray(doc.base) ? doc.base : [doc.base];
    if (rawBases.length === 0) errors.push(`${ctx}: "base" must name at least one item`);
    bases = rawBases.map((b, i) =>
      resolveItem(b, `${ctx} › base${rawBases.length > 1 ? ' ' + (i + 1) : ''}`, errors, catalog),
    );
  }

  let ilvl;
  if (doc.ilvl != null) {
    if (!Number.isInteger(doc.ilvl) || doc.ilvl <= 0) errors.push(`${ctx}: "ilvl" must be a positive whole number`);
    else ilvl = doc.ilvl;
  }

  const stepsRaw = Array.isArray(doc.steps) ? doc.steps : null;
  if (!stepsRaw || stepsRaw.length === 0) errors.push(`${ctx}: "steps" must be a non-empty list`);
  const stepIds = new Set();
  const steps = (stepsRaw ?? []).map((s, i) =>
    validateStep(s, `${ctx} › step ${i + 1}`, errors, catalog, stepIds),
  );

  const guide = { id: id ?? '', slot: slot ?? '', name: name ?? '', goal: goal ?? '', bases, steps };
  if (ilvl != null) guide.ilvl = ilvl;
  if (doc.author != null) guide.author = validateAuthor(doc.author, ctx, errors);

  if (doc.result != null) {
    if (!Array.isArray(doc.result)) errors.push(`${ctx}: "result" must be a list`);
    else {
      guide.result = doc.result.map((r, i) => validateResultMod(r, `${ctx} › result ${i + 1}`, errors));
      if (guide.result.length > 0 && !guide.result.some((r) => !r.alt)) {
        errors.push(`${ctx}: "result" needs at least one required mod (not all "alt")`);
      }
    }
  }

  return guide;
}

function render(guides) {
  return `// AUTO-GENERATED — do not edit by hand.
// Source: guides/*.yaml  ·  Regenerate: bun run crafting
import type { CraftingGuideData } from './crafting';

export const CRAFTING_GUIDES: CraftingGuideData[] = ${JSON.stringify(guides, null, 2)};
`;
}

function main() {
  const catalog = loadIconMap();
  if (catalog.size === 0) {
    console.error('[crafting] Item dataset has no icons. Re-run `bun run consolidate` on the website.');
    process.exit(1);
  }

  const errors = [];
  const guides = [];
  const ids = new Set();

  const files = existsSync(GUIDES_DIR)
    ? readdirSync(GUIDES_DIR).filter((f) => /\.ya?ml$/i.test(f)).sort()
    : [];

  if (files.length === 0) {
    console.error(`[crafting] No guide files found in guides/. Add a guides/*.yaml file.`);
    process.exit(1);
  }

  for (const file of files) {
    const ctx = `guides/${file}`;
    let doc;
    try {
      doc = parseYaml(readFileSync(join(GUIDES_DIR, file), 'utf8'));
    } catch (e) {
      errors.push(`${ctx}: YAML syntax error — ${e.message}`);
      continue;
    }
    if (!doc || typeof doc !== 'object') {
      errors.push(`${ctx}: file is empty or not a mapping`);
      continue;
    }
    guides.push(validateGuide(doc, ctx, errors, catalog, ids));
  }

  if (errors.length > 0) {
    console.error(`\n[crafting] ${errors.length} problem(s) found in guides/:\n`);
    for (const e of errors) console.error(`  ✗ ${e}`);
    console.error('');
    process.exit(1);
  }

  writeFileSync(OUT_FILE, render(guides));
  console.log(`[crafting] Compiled ${guides.length} guide(s) from ${files.length} file(s) (${catalog.size} icons in catalog).`);
}

main();
